import React from "react";

export default function FormSection({
  title,
  sectionKey,
  openSections,
  toggleSection,
  hasError,
  children,
}) {
  return (
    <div className="mb-4 border p-3 rounded">
      <button
        type="button"
        className="btn btn-link p-0 mb-2"
        onClick={() => toggleSection(sectionKey)}
      >
        {title} {openSections[sectionKey] ? "▲" : "▼"}{" "}
        {hasError && <span className="text-danger">⚠️</span>}
      </button>
      {openSections[sectionKey] && <div>{children}</div>}
    </div>
  );
}

export default function InputField({
  id,
  name,
  label,
  type = "text",
  value,
  onChange,
  onBlur,
  touched = false,
  required = false,
  error = "",
  submitted = false,
  hideLabel = false,
  helpText = "",
  maxLength,
  ...props
}) {
  const hasError = Boolean(error) || (required && (touched || submitted) && !value);

  return (
    <div className="mb-3">
      {!hideLabel && (
        <label htmlFor={id || name} className="form-label">
          {label} {required && "*"}
        </label>
      )}

      <input
        type={type}
        id={id || name}
        name={name}
        className={`form-control ${hasError ? "is-invalid" : ""}`}
        value={value ?? ""}
        onChange={(e) => onChange?.(e.target.value)}
        onBlur={() => onBlur?.(name)}
        maxLength={maxLength}    
        {...props}
      />

      {hasError && (
        <small className="text-danger">
          {error || "Ce champ est obligatoire"}
        </small>
      )}
    </div>
  );
}

import React from "react";

export default function SelectField({
  label,
  name,
  value,
  onChange,
  onBlur,
  touched,      // ✅ vient du hook
  options = [],
  required = false,
  error,
  submitted = false,
  ...props
}) {
  const hasError =
    (required && touched && !value) ||
    (required && submitted && !value) ||
    Boolean(error);

  return (
    <div className="mb-3">
      <label className="form-label">
        {label} {required && "*"}
      </label>
      <select
        name={name}
        className={`form-control ${hasError ? "is-invalid" : ""}`}
        value={value || ""}
        onChange={(e) => onChange?.(e.target.value)}  
        onBlur={() => onBlur?.(name)}   // appelle handleBlur(field) du hook
        {...props}
      >
        <option value="">-- Sélectionner --</option>
        {options.map((opt) => (
          <option key={opt.value} value={opt.value}>
            {opt.label}
          </option>
        ))}
      </select>
      {hasError && (
        <small className="text-danger">
          {error || "Ce champ est obligatoire"}
        </small>
      )}
    </div>
  );
}

