// utils/validators/contact.js
import { validateEmail, validateOptionalEmail } from "./email";

export function validateContact(data, options = {}) {
  const errors = {};
  const {
    emailField = "email",
    emailRequired = false,
    phoneField = "phone",
  } = options;

  const emailValue = data[emailField];
  const phoneValue = data[phoneField];

  // Email
  const emailError = emailRequired
    ? validateEmail(emailValue)
    : validateOptionalEmail(emailValue);

  if (emailError) errors[emailField] = emailError;

  // Téléphone
  if (phoneValue && !/^\+?[0-9\s-]{6,20}$/.test(phoneValue)) {
    errors[phoneField] = "Numéro de téléphone invalide";
  }

  return errors;
}

import { isValidSiret } from './siret';
import { validateContact } from './contact';
import { isValidPostalCode } from './postal_code';

export function validateClient(data) {
  const errors = {};

  const isCompany = data.is_company ?? true;

  // ---------------------
  // Validation légale
  // ---------------------
  if (isCompany) {
    if (!data.legal_name?.trim()) {
      errors.legal_name = 'Le nom légal est obligatoire';
    }

    if (data.country_code === 'FR') {
      const siret = (data.siret || '').replace(/\D/g, '');
      if (!siret) {
        errors.siret = 'Le SIRET est requis pour une entreprise française';
      } else if (siret.length !== 14) {
        errors.siret = 'Le SIRET doit contenir 14 chiffres';
      } else if (!isValidSiret(siret)) {
        errors.siret = 'SIRET invalide';
      }
    } else if (!data.vat_number?.trim()) {
      errors.vat_number = 'Le numéro de TVA intracommunautaire est requis';
    }
  } else {
    // Personne physique
    if (!data.firstname?.trim()) {
      errors.firstname = 'Le prénom est obligatoire';
    }
    if (!data.lastname?.trim()) {
      errors.lastname = 'Le nom est obligatoire';
    }

    if (data.siret) {
      errors.siret = 'Un particulier ne peut pas avoir de SIRET';
    }
  }

  // ---------------------
  // Validation contact
  // ---------------------
  const contactErrors = validateContact(data, { emailField: 'email', emailRequired: false });

  // ---------------------
  // Validation adresse
  // ---------------------
  if (data.country_code === 'FR' && !isValidPostalCode(data.postal_code)) {
    errors.postal_code = 'Le code postal doit contenir 5 chiffres';
  }

  return {
    ...errors,
    ...contactErrors
  };
}

import { useAuth0 } from "@auth0/auth0-react";
import { useCallback } from "react";
import { getEnv } from "@/utils/getEnv";

export function useAuth() {
  const { getAccessTokenSilently } = useAuth0();

  const getToken = useCallback(async () => {
    try {
      const env = getEnv(); 
      const audience = env.VITE_AUTH0_AUDIENCE;

      const token = await getAccessTokenSilently({
        authorizationParams: { audience },
      });

      // Vérification du format du token
      const parts = token.split(".");
      if (parts.length === 5) {
        console.warn("[Auth] Format JWE (token chiffré) ⚠️");
      } else if (parts.length !== 3) {
        console.warn("[Auth] Format token inattendu ⚠️");
      }

      return token;
    } catch (err) {
      console.error("Impossible de récupérer le token", err);
      throw err;
    }
  }, [getAccessTokenSilently]);

  return { getToken };
}

import { useMemo } from "react";
import { useAuth } from "@/hooks/useAuth";
import { getEnv } from "@/utils/getEnv";

const env = getEnv();
const API_ROOT = (env.VITE_API_URL || 'http://localhost:8080').replace(/\/$/, '');
const API_BASE = `${API_ROOT}/api/clients`;

export function useClientService() {
  const { getToken } = useAuth();

  return useMemo(() => {
    const request = async (url, options = {}) => {
      const token = await getToken();     
      const res = await fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${token}`,
        },
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status}: ${text}`);
      }

      return res.status === 204 ? true : res.json();
    };

    return {
      fetchClients: () => request(API_BASE),
      fetchClient: (id) => request(`${API_BASE}/${id}`),
      createClient: (data) =>
        request(API_BASE, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(data),
        }),
      updateClient: (id, data) =>
        request(`${API_BASE}/${id}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(data),
        }),
      deleteClient: (id) => request(`${API_BASE}/${id}`, { method: "DELETE" }),
      checkSiret: (siret, clientId = null) => {
        const url = new URL(`${API_BASE}/check-siret/${siret}`);
        if (clientId) url.searchParams.append("id", clientId);
        return request(url.toString());
      },
    };
  }, [getToken]);
}

import { useState, useCallback } from 'react';
import { validateClient } from '../../utils/validators/client';
import { useClientService } from '@/services/clients';

export default function useClientForm(initialData = {}) {

  const [formData, setFormData] = useState({
    is_company: true,
    legal_name: '',
    firstname: '',
    lastname: '',
    siret: '',
    legal_identifier: '',
    address: '',
    city: '',
    postal_code: '',
    country_code: 'FR',
    vat_number: '',
    email: '',
    phone: '',
    ...initialData,
  });

  const [errors, setErrors] = useState({});
  const [touched, setTouched] = useState({});
  const [openSections, setOpenSections] = useState({
    legal: true,
    contact: true,
    address: true,
    finances: true,
  });

  const { checkSiret } = useClientService();

  // ✅ Stabilisation avec useCallback
  const checkSiretAPI = useCallback(async (siret) => {
    if (!siret || siret.length !== 14) return { valid: true };

    try {
      const result = await checkSiret(siret, formData.id || undefined);
      if (result.exists) {
        setErrors(prev => ({ ...prev, siret: 'Ce SIRET est déjà utilisé par un autre client' }));
        return { valid: false };
      } else {
        setErrors(prev => ({ ...prev, siret: undefined }));
        return { valid: true };
      }
    } catch (err) {
      console.error(err);
      setErrors(prev => ({ ...prev, siret: 'Impossible de vérifier le SIRET' }));
      return { valid: false };
    }
  }, [checkSiret, formData.id]);

  // ----------------------
  // Handle Change
  // ----------------------
  const handleChange = (field, value) => {
    setFormData(prev => {
      const updated = { ...prev, [field]: value };

      const fieldError = validateClient(updated, field);
      setErrors(prevErrors => {
        if (field === 'siret' && prevErrors.siret?.includes('déjà utilisé')) return prevErrors;
        return { ...prevErrors, [field]: fieldError[field] };
      });

      if (field === 'siret') {
        const cleaned = (value || '').replace(/\D/g, '');
        if (cleaned.length === 14) { 
          checkSiretAPI(cleaned); 
        }               
      }

      return updated;
    });
  };

  // ----------------------
  // Handle Blur
  // ----------------------
  const handleBlur = (field) => {
    setTouched(prev => ({ ...prev, [field]: true }));

    const fieldError = validateClient(formData, field);
    setErrors(prevErrors => {
      if (field === 'siret' && prevErrors.siret?.includes('déjà utilisé')) {
        return prevErrors;
      }
      return { ...prevErrors, [field]: fieldError[field] };
    });

    if (field === 'siret') {
      const cleaned = (formData.siret || '').replace(/\D/g, '');
      if (cleaned.length === 14) {
        checkSiretAPI(cleaned);
      }
    }
  };

  // ----------------------
  // Toggle section
  // ----------------------
  const toggleSection = (section) => {
    setOpenSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  return {
    formData,
    setFormData,
    errors,
    setErrors,
    touched,
    setTouched,
    openSections,
    toggleSection,
    handleChange,
    handleBlur,
    checkSiretAPI, 
  };
}

import React from 'react';
import countries from "i18n-iso-countries";
import enLocale from "i18n-iso-countries/langs/en.json";

import LegalFields from './fields/LegalFields';
import ContactFields from './fields/ContactFields';
import AddressFields from './fields/AddressFields';
import FinanceFields from './fields/FinanceFields';
import useClientForm from '../../modules/clients/useClientForm';
import { validateClient } from '../../utils/validators/client';

countries.registerLocale(enLocale);
const countryCodes = Object.entries(countries.getNames("en")).map(([code, name]) => ({ code, name }));

export default function ClientForm({ onSubmit, disabled = false, initialData = {} }) {
  const {
    formData,
    errors,
    touched,
    openSections,
    toggleSection,
    handleChange,
    handleBlur,
    setErrors,
    setTouched,
    checkSiretAPI
  } = useClientForm(initialData);

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Marquer tous les champs comme touchés
    const allTouched = Object.keys(formData).reduce((acc, key) => ({ ...acc, [key]: true }), {});
    setTouched(allTouched);

    // Nettoyage SIRET
    const cleanedSiret = (formData.siret || '').toString().replace(/\D/g, '');

    // Validation locale
    const newErrors = validateClient({ ...formData, siret: cleanedSiret });
    setErrors(newErrors);

    // Vérification SIRET côté API si FR
    if (formData.is_company && formData.country_code === 'FR' && cleanedSiret) {
      const result = await checkSiretAPI(cleanedSiret);
      if (!result.valid) {
        // Ouvre la section legal si erreur SIRET
        if (!openSections.legal) toggleSection('legal');
        return; // stop l'envoi
      }
    }

    // Ouvrir les sections avec erreurs locales
    Object.keys(openSections).forEach(section => {
      if (sectionHasError(section, newErrors, touched) && !openSections[section]) {
        toggleSection(section);
      }
    });

    // Envoi si pas d'erreurs
    if (Object.keys(newErrors).length === 0 && onSubmit) {
      const payload = {
        ...formData,
        is_company: !!formData.is_company,
        legal_name: formData.is_company
          ? formData.legal_name?.trim()
          : `${formData.firstname?.trim() || ''} ${formData.lastname?.trim() || ''}`.trim(),
        siret: formData.is_company && formData.country_code === 'FR' ? cleanedSiret : null,
        legal_identifier: formData.is_company
          ? formData.country_code === 'FR'
            ? cleanedSiret
            : formData.vat_number?.trim() || null
          : null,
      };
      onSubmit(payload);
    }
  };

  const sections = [
    { key: 'legal', label: 'Informations légales', component: LegalFields },
    { key: 'contact', label: 'Contact', component: ContactFields },
    { key: 'address', label: 'Adresse', component: AddressFields },
    { key: 'finances', label: 'Finances', component: FinanceFields }
  ];

  return (
    <form onSubmit={handleSubmit} className="p-3 border rounded bg-light">
      {sections.map(({ key, label, component }) => {
        const hasError = sectionHasError(key, errors, touched);
        const Component = component;

        return (
          <div className="mb-3" key={key}>
            <button type="button" className="btn btn-link p-0 mb-2" onClick={() => toggleSection(key)}>
              {label} {openSections[key] ? '▲' : '▼'} {hasError && '⚠️'}
            </button>
            {openSections[key] && (
              <Component
                formData={formData}
                errors={errors}
                touched={touched}
                handleChange={handleChange}
                handleBlur={handleBlur}
                disabled={disabled}
                countryCodes={key === 'address' ? countryCodes : undefined}
              />
            )}
          </div>
        );
      })}

      {!disabled && (
        <div className="text-end mt-3">
          <button type="submit" className="btn btn-primary">Enregistrer</button>
        </div>
      )}
    </form>
  );
}

// ---------------------
// Helper pour savoir si une section contient des erreurs
// ---------------------
function sectionHasError(section, errors, touched) {
  const mapping = {
    legal: ['legal_name', 'siret', 'legal_identifier', 'firstname', 'lastname'],
    contact: ['email', 'phone'],
    address: ['address', 'city', 'postal_code', 'country_code'],
    finances: ['vat_number']
  };

  return Object.keys(errors).some(
    key => mapping[section]?.includes(key) && touched[key] && Boolean(errors[key])
  );
}
